import type { Metadata, Viewport } from "next";
import "./globals.css";

export const metadata: Metadata = {
  metadataBase: new URL("https://localhost:3000"),
  title: {
    default: "Notepad Pro",
    template: "%s · Notepad Pro",
  },
  description:
    "A modern, desktop-inspired notepad application built with Next.js. Supports multi-document workflows, editing tools, and reliable local file operations.",
  applicationName: "Notepad Pro",
  keywords: [
    "notepad",
    "text editor",
    "next.js",
    "productivity",
    "txt",
    "rtf",
  ],
};

export const viewport: Viewport = {
  width: "device-width",
  initialScale: 1,
  themeColor: [
    { media: "(prefers-color-scheme: light)", color: "#f8fafc" },
    { media: "(prefers-color-scheme: dark)", color: "#0b1120" },
  ],
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="en">
      <body>
        <a href="#main-content" className="skip-link">
          Skip to main content
        </a>

        <div className="app-shell">
          <header className="app-header" role="banner">
            <div className="app-header__inner">
              <div className="app-brand">
                <span className="app-brand__dot" aria-hidden="true" />
                <div>
                  <h1 className="app-title">Notepad Pro</h1>
                  <p className="app-subtitle">Desktop-style text editing, built for the web</p>
                </div>
              </div>
              <div className="app-badge" aria-label="Build status">
                Production Ready
              </div>
            </div>
          </header>

          <main id="main-content" className="app-main" role="main">
            {children}
          </main>

          <footer className="app-footer" role="contentinfo">
            <p>
              © {new Date().getFullYear()} Notepad Pro · Responsive foundation scaffold for
              multi-document editing workflows.
            </p>
          </footer>
        </div>
      </body>
    </html>
  );
}

@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  color-scheme: light;

  --background: #f3f6fb;
  --background-elevated: #ffffff;
  --background-muted: #eef2ff;
  --foreground: #0f172a;
  --foreground-muted: #475569;

  --border: #dbe3f0;
  --border-strong: #b9c6db;

  --primary: #2563eb;
  --primary-strong: #1d4ed8;
  --primary-soft: #dbeafe;

  --success: #15803d;
  --warning: #b45309;
  --danger: #b91c1c;

  --shadow-sm: 0 1px 2px rgba(2, 6, 23, 0.08);
  --shadow-md: 0 12px 30px rgba(15, 23, 42, 0.08);

  --radius-sm: 0.5rem;
  --radius-md: 0.75rem;
  --radius-lg: 1rem;

  --space-1: 0.25rem;
  --space-2: 0.5rem;
  --space-3: 0.75rem;
  --space-4: 1rem;
  --space-5: 1.25rem;
  --space-6: 1.5rem;
  --space-8: 2rem;

  --container: 1200px;
  --header-height: 72px;

  --ring: 0 0 0 3px rgba(37, 99, 235, 0.25);
}

@media (prefers-color-scheme: dark) {
  :root {
    color-scheme: dark;

    --background: #0b1120;
    --background-elevated: #111a2c;
    --background-muted: #1a2742;
    --foreground: #e2e8f0;
    --foreground-muted: #94a3b8;

    --border: #24324d;
    --border-strong: #334866;

    --primary: #60a5fa;
    --primary-strong: #3b82f6;
    --primary-soft: rgba(59, 130, 246, 0.2);

    --success: #22c55e;
    --warning: #f59e0b;
    --danger: #f87171;

    --shadow-sm: 0 1px 2px rgba(0, 0, 0, 0.3);
    --shadow-md: 0 18px 36px rgba(0, 0, 0, 0.4);

    --ring: 0 0 0 3px rgba(96, 165, 250, 0.35);
  }
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
  min-height: 100%;
}

body {
  font-family: "Inter", "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
  background:
    radial-gradient(circle at 20% -10%, rgba(37, 99, 235, 0.08), transparent 35%),
    radial-gradient(circle at 95% 10%, rgba(59, 130, 246, 0.08), transparent 25%),
    var(--background);
  color: var(--foreground);
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

a {
  color: inherit;
  text-decoration: none;
}

.skip-link {
  position: absolute;
  left: 1rem;
  top: -100%;
  z-index: 1000;
  background: var(--primary);
  color: #fff;
  padding: 0.625rem 0.875rem;
  border-radius: var(--radius-sm);
  font-weight: 600;
  transition: top 0.2s ease;
}

.skip-link:focus-visible {
  top: 1rem;
}

.app-shell {
  min-height: 100dvh;
  display: grid;
  grid-template-rows: auto 1fr auto;
}

.app-header {
  position: sticky;
  top: 0;
  z-index: 50;
  backdrop-filter: saturate(160%) blur(10px);
  background: color-mix(in srgb, var(--background-elevated) 88%, transparent);
  border-bottom: 1px solid var(--border);
  box-shadow: var(--shadow-sm);
}

.app-header__inner {
  min-height: var(--header-height);
  width: min(calc(100% - 2rem), var(--container));
  margin-inline: auto;
  padding: var(--space-4) 0;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-4);
}

.app-brand {
  display: flex;
  align-items: center;
  gap: var(--space-3);
  min-width: 0;
}

.app-brand__dot {
  width: 0.75rem;
  height: 0.75rem;
  border-radius: 999px;
  background: linear-gradient(130deg, var(--primary), #7dd3fc);
  box-shadow: 0 0 0 4px color-mix(in srgb, var(--primary) 22%, transparent);
  flex-shrink: 0;
}

.app-title {
  margin: 0;
  line-height: 1.1;
  letter-spacing: -0.02em;
  font-size: clamp(1rem, 1.3vw, 1.25rem);
  font-weight: 700;
}

.app-subtitle {
  margin: 0.2rem 0 0;
  color: var(--foreground-muted);
  font-size: 0.875rem;
  line-height: 1.2;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  max-width: min(70vw, 680px);
}

.app-badge {
  display: inline-flex;
  align-items: center;
  border: 1px solid var(--border-strong);
  background: var(--background-muted);
  color: var(--foreground);
  font-size: 0.75rem;
  font-weight: 600;
  letter-spacing: 0.02em;
  border-radius: 999px;
  padding: 0.375rem 0.625rem;
  flex-shrink: 0;
}

.app-main {
  width: min(calc(100% - 2rem), var(--container));
  margin-inline: auto;
  padding: var(--space-6) 0 var(--space-8);
  display: flex;
  flex-direction: column;
  gap: var(--space-6);
}

.app-footer {
  width: min(calc(100% - 2rem), var(--container));
  margin-inline: auto;
  padding: var(--space-4) 0 var(--space-6);
  color: var(--foreground-muted);
  font-size: 0.875rem;
  border-top: 1px solid color-mix(in srgb, var(--border) 70%, transparent);
}

@layer components {
  .surface {
    background: var(--background-elevated);
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
    box-shadow: var(--shadow-md);
  }

  .panel {
    background: var(--background-elevated);
    border: 1px solid var(--border);
    border-radius: var(--radius-md);
    box-shadow: var(--shadow-sm);
  }

  .toolbar {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    gap: var(--space-2);
  }

  .btn {
    border: 1px solid var(--border-strong);
    border-radius: var(--radius-sm);
    background: var(--background-elevated);
    color: var(--foreground);
    font: inherit;
    font-weight: 600;
    padding: 0.5rem 0.8rem;
    transition: transform 0.15s ease, border-color 0.2s ease, background-color 0.2s ease;
  }

  .btn:hover {
    border-color: var(--primary-strong);
    background: var(--primary-soft);
    transform: translateY(-1px);
  }

  .btn:active {
    transform: translateY(0);
  }

  .btn:focus-visible,
  .input:focus-visible,
  .textarea:focus-visible,
  .select:focus-visible {
    outline: none;
    box-shadow: var(--ring);
  }

  .btn-primary {
    border-color: var(--primary);
    background: var(--primary);
    color: #fff;
  }

  .btn-primary:hover {
    border-color: var(--primary-strong);
    background: var(--primary-strong);
  }

  .input,
  .textarea,
  .select {
    width: 100%;
    border: 1px solid var(--border-strong);
    border-radius: var(--radius-sm);
    background: var(--background-elevated);
    color: var(--foreground);
    font: inherit;
    line-height: 1.4;
    padding: 0.55rem 0.7rem;
    transition: border-color 0.2s ease;
  }

  .textarea {
    min-height: 240px;
    resize: vertical;
  }

  .status-bar {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    justify-content: space-between;
    gap: var(--space-3);
    border-top: 1px solid var(--border);
    color: var(--foreground-muted);
    font-size: 0.8125rem;
    padding-top: var(--space-3);
  }
}

@layer utilities {
  .text-balance {
    text-wrap: balance;
  }

  .text-muted {
    color: var(--foreground-muted);
  }

  .stack-md {
    display: grid;
    gap: var(--space-4);
  }

  .stack-lg {
    display: grid;
    gap: var(--space-6);
  }
}

@media (max-width: 768px) {
  :root {
    --header-height: 64px;
  }

  .app-header__inner {
    width: min(calc(100% - 1.25rem), var(--container));
    padding: var(--space-3) 0;
  }

  .app-main,
  .app-footer {
    width: min(calc(100% - 1.25rem), var(--container));
  }

  .app-subtitle {
    max-width: 58vw;
  }

  .app-badge {
    font-size: 0.7rem;
  }
}

@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.001ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.001ms !important;
    scroll-behavior: auto !important;
  }
}
